#define MAX_THREADS 1024

typedef float fp;

__kernel void extract_kernel(long d_Ne,
                             __global fp *d_I)
{
    long ei = (long)get_global_id(0);
    if (ei < d_Ne) {
        d_I[ei] = exp(d_I[ei] / (fp)255.0f);
    }
}

__kernel void prepare_kernel(long d_Ne,
                             __global fp *d_I,
                             __global fp *d_sums,
                             __global fp *d_sums2)
{
    long ei = (long)get_global_id(0);
    if (ei < d_Ne) {
        fp v = d_I[ei];
        d_sums[ei] = v;
        d_sums2[ei] = v * v;
    }
}

__kernel void reduce_kernel(long d_Ne,
                            int d_no,
                            int d_mul,
                            __global fp *d_sums,
                            __global fp *d_sums2,
                            int blocks_work_size)
{
    (void)d_Ne;

    int bx = (int)get_group_id(0);
    int tx = (int)get_local_id(0);
    int local_sz = (int)get_local_size(0);
    int ei = bx * local_sz + tx;
    int nf = local_sz - (blocks_work_size * local_sz - d_no);
    int df = 0;

    __local fp d_psum[MAX_THREADS];
    __local fp d_psum2[MAX_THREADS];

    if (tx < MAX_THREADS) {
        if (ei < d_no) {
            d_psum[tx] = d_sums[ei * d_mul];
            d_psum2[tx] = d_sums2[ei * d_mul];
        } else {
            d_psum[tx] = (fp)0.0f;
            d_psum2[tx] = (fp)0.0f;
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    if (nf == local_sz) {
        for (int i = 2; i <= local_sz; i <<= 1) {
            if (((tx + 1) % i) == 0) {
                d_psum[tx] = d_psum[tx] + d_psum[tx - (i >> 1)];
                d_psum2[tx] = d_psum2[tx] + d_psum2[tx - (i >> 1)];
            }
            barrier(CLK_LOCAL_MEM_FENCE);
        }

        if (tx == (local_sz - 1)) {
            d_sums[bx * d_mul * local_sz] = d_psum[tx];
            d_sums2[bx * d_mul * local_sz] = d_psum2[tx];
        }
    } else {
        if (bx != (blocks_work_size - 1)) {
            for (int i = 2; i <= local_sz; i <<= 1) {
                if (((tx + 1) % i) == 0) {
                    d_psum[tx] = d_psum[tx] + d_psum[tx - (i >> 1)];
                    d_psum2[tx] = d_psum2[tx] + d_psum2[tx - (i >> 1)];
                }
                barrier(CLK_LOCAL_MEM_FENCE);
            }

            if (tx == (local_sz - 1)) {
                d_sums[bx * d_mul * local_sz] = d_psum[tx];
                d_sums2[bx * d_mul * local_sz] = d_psum2[tx];
            }
        } else {
            for (int i = 2; i <= local_sz; i <<= 1) {
                if (nf >= i) {
                    df = i;
                }
            }

            for (int i = 2; i <= df; i <<= 1) {
                if (((tx + 1) % i) == 0 && tx < df) {
                    d_psum[tx] = d_psum[tx] + d_psum[tx - (i >> 1)];
                    d_psum2[tx] = d_psum2[tx] + d_psum2[tx - (i >> 1)];
                }
                barrier(CLK_LOCAL_MEM_FENCE);
            }

            if (tx == (df - 1)) {
                for (int i = (bx * local_sz) + df; i < (bx * local_sz) + nf; i++) {
                    d_psum[tx] = d_psum[tx] + d_sums[i];
                    d_psum2[tx] = d_psum2[tx] + d_sums2[i];
                }

                d_sums[bx * d_mul * local_sz] = d_psum[tx];
                d_sums2[bx * d_mul * local_sz] = d_psum2[tx];
            }
        }
    }
}

__kernel void srad_kernel(fp lambda,
                          int Nr,
                          int Nc,
                          long Ne,
                          __global int *d_iN,
                          __global int *d_iS,
                          __global int *d_jE,
                          __global int *d_jW,
                          __global fp *d_dN,
                          __global fp *d_dS,
                          __global fp *d_dW,
                          __global fp *d_dE,
                          fp d_q0sqr,
                          __global fp *d_c,
                          __global fp *d_I)
{
    (void)lambda;

    long ei = (long)get_global_id(0);
    if (ei < Ne) {
        int row = (int)(ei / (long)Nc);
        int col = (int)(ei % (long)Nc);

        fp Jc = d_I[ei];

        fp dN = d_I[d_iN[row] * Nc + col] - Jc;
        fp dS = d_I[d_iS[row] * Nc + col] - Jc;
        fp dW = d_I[row * Nc + d_jW[col]] - Jc;
        fp dE = d_I[row * Nc + d_jE[col]] - Jc;

        d_dN[ei] = dN;
        d_dS[ei] = dS;
        d_dW[ei] = dW;
        d_dE[ei] = dE;

        fp G2 = (dN * dN + dS * dS + dW * dW + dE * dE) / (Jc * Jc);
        fp L = (dN + dS + dW + dE) / Jc;

        fp num = (fp)0.5f * G2 - (fp)0.0625f * (L * L);
        fp den = (fp)1.0f + (fp)0.25f * L;
        fp qsqr = num / (den * den);

        den = (qsqr - d_q0sqr) / (d_q0sqr * ((fp)1.0f + d_q0sqr));
        fp c = (fp)1.0f / ((fp)1.0f + den);

        if (c < (fp)0.0f) {
            c = (fp)0.0f;
        } else if (c > (fp)1.0f) {
            c = (fp)1.0f;
        }

        d_c[ei] = c;
    }
}

__kernel void srad2_kernel(fp lambda,
                           int Nr,
                           int Nc,
                           long Ne,
                           __global int *d_iN,
                           __global int *d_iS,
                           __global int *d_jE,
                           __global int *d_jW,
                           __global fp *d_dN,
                           __global fp *d_dS,
                           __global fp *d_dW,
                           __global fp *d_dE,
                           __global fp *d_c,
                           __global fp *d_I)
{
    (void)Nr;
    (void)d_iN;
    (void)d_jW;

    long ei = (long)get_global_id(0);
    if (ei < Ne) {
        int row = (int)(ei / (long)Nc);
        int col = (int)(ei % (long)Nc);

        fp cN = d_c[ei];
        fp cS = d_c[d_iS[row] * Nc + col];
        fp cW = d_c[ei];
        fp cE = d_c[row * Nc + d_jE[col]];

        fp D = cN * d_dN[ei] + cS * d_dS[ei] + cW * d_dW[ei] + cE * d_dE[ei];
        d_I[ei] = d_I[ei] + (fp)0.25f * lambda * D;
    }
}

__kernel void compress_kernel(long d_Ne,
                              __global fp *d_I)
{
    long ei = (long)get_global_id(0);
    if (ei < d_Ne) {
        d_I[ei] = log(d_I[ei]) * (fp)255.0f;
    }
}
